export const hotelProperties = hotelDefinitions.map(({ id, name }) => ({ id, name }));

export const getHotelDefinition = (propertyId: string) => (
  hotelDefinitions.find((hotel) => hotel.id === propertyId)
);

export const getHotelSourceTypes = (propertyId: string) => (
  getHotelDefinition(propertyId)?.sourceTypes ?? []
);

export const getHotelDepartments = (propertyId: string) => (
  getHotelDefinition(propertyId)?.departments.filter((department) => !department.isPassive) ?? []
);

export const getHotelSubDepartments = (propertyId: string, departmentName?: string) => {
  const subDepartments = getHotelDefinition(propertyId)?.subDepartments ?? [];
  if (!departmentName) return subDepartments;
  return subDepartments.filter((subDepartment) => subDepartment.department === departmentName);
};

export const getHotelTaskDefinitions = (propertyId: string) => (
  getHotelDefinition(propertyId)?.taskDefinitions.filter((task) => !task.isPassive) ?? []
);

export const getHotelEmployees = (propertyId: string) => (
  getHotelDefinition(propertyId)?.employees.filter((employee) => !employee.isPassive && !employee.isDeleted) ?? []
);

export const hotelEmployees = hotelDefinitions.flatMap((hotel) =>
  hotel.employees
    .filter((employee) => !employee.isPassive && !employee.isDeleted)
    .map((employee) => ({ ...employee, propertyId: hotel.id, property: hotel.name }))
);
